def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                factor = (a ** 3) * np.sin(ratio * np.pi * a)
                temp = np.exp(-ratio * a**1.3) * factor
                if a % 4 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.1
                score += temp
            if int(capacity + item) % 4 == 0 or int(abs(capacity - item)) % 7 == 0:
                score *= 0.82
            if score > 10:
                score /= 3.3
            if score < 0:
                score = -score * 1.1 + 0.5
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, int(capacity) + 3):
                term = ratio + n / (n + 1) - np.cos(ratio * n)
                prod *= abs(term) + 0.01
                if prod > 2e6:
                    prod = np.log1p(prod) * 2
                    break
            mod_val = int(prod) % 325
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                score += 6.1
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 3.1) * np.log1p(x)
            score += extra_sum / 7
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                exponent = m + 1.7
                increment = (ratio ** exponent) * (m ** 3.1) / ((m + 1.2) ** 1.1)
                score += increment * np.sin(m)
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.75
                if remainder < 0:
                    score += abs(remainder) * 4.2
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 18:
                score /= 3.7
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 12):
                power_term = ((ratio - 0.55) ** p) * (p ** 1.8) * np.cos(p)
                penalty_base += power_term
                if penalty_base > 80:
                    penalty_base = np.log1p(abs(penalty_base)) * 1.3
                    break
            score = penalty_base * 15
            if capacity < item * 1.08:
                score += 18
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.25:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.5) * np.sin(q**0.5)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 26
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 9
            for z in range(1, 9):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1600:
                score = 1600
        else:
            super_penalty = 0
            diff = ratio - 1.25
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5) * np.cos(r * np.pi / 5)
                if term > 15000:
                    term = np.sqrt(abs(term)) * np.sign(term)
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 11) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5) * np.sin(w)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2500:
                score = 2500
        if capacity > 250:
            score /= (np.sqrt(capacity) + 2)
        elif capacity < 3:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        adjusted_max = np.max(finite_priorities) * (10 + top_count * 2) - median_val * 1.1
        fill_value = max(adjusted_max, median_val)
    priorities[np.isinf(priorities)] = fill_value
    nan_indices = np.isnan(priorities)
    median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    priorities[nan_indices] = median_finite + np.random.uniform(-0.1, 0.1, size=np.sum(nan_indices))
    return priorities
